script.text:

function init$Form$&Controller;(f) {setDefaultValue$Form$&Controller;(f);}
function active$Form$&Controller;(f) {f.add_onResponseComplete(on$Form$&Controller;$ResponseComplete);}
function scatter$Form$&Controller;(f) {setDefaultValue$Form$&Controller;(f);}
function close$Form$&Controller;(f) {try {f.remove_onResponseComplete(on$Form$&Controller;$ResponseComplete)} catch (ex) {}}
function on$Form$&Controller;$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_kieu');
      var u = parseInt(f.getItemValue('dvcs')) + parseInt(f.getItemValue('ma_bp')) + parseInt(f.getItemValue('tk')) + parseInt(f.getItemValue('nh_kh1')) + parseInt(f.getItemValue('nh_kh2')) + parseInt(f.getItemValue('nh_kh3')) + parseInt(f.getItemValue('so_luong')) + parseInt(f.getItemValue('tien')) + parseInt(f.getItemValue('loai_ct'));
      if (u == 0) {
        var msg = (f._language == 'v' ? 'Chưa khai báo thông tin để xác định kiểu duyệt.' : 'One of approval category determination field must be checked.');
        f._checked = false;
        $func.hideWait(f.get_id());
        $message.show(msg, String.format('$find(\'{0}\').getItem(\'' + ('ma_kieu') + '\').focus();', f.get_id()));
        return false;
      }
      break;
    default:
      break;
  }
}
function setDefaultValue$Form$&Controller;(f) {
  var g = f.grid;
  if (f._action == 'New') f.setItemValue('loai_duyet', g._approvalType);
  setObjectFormHidden(f, 'dvcs', !g._dvcs_yn);
  setObjectFormHidden(f, 'ma_bp', !g._bp_yn);
  setObjectFormHidden(f, 'tk', !g._tk_yn);
  setObjectFormHidden(f, 'nh_kh1', !g._kh_yn);
  setObjectFormHidden(f, 'nh_kh2', !g._kh_yn);
  setObjectFormHidden(f, 'nh_kh3', !g._kh_yn);
  setObjectFormHidden(f, 'so_luong', !g._sl_yn);
  setObjectFormHidden(f, 'tien', !g._tien_yn);
  setObjectFormHidden(f, 'loai_ct', !g._loai_ct_yn);
}
function onChange$Form$&Controller;$Amount(o) {
  var f = o.parentForm;
  f.setItemValue('ma_nt', f.getItemValue('tien'));
}
function setObjectFormHidden(f, c, b) {if (b) {$common.setVisible(f.getItem(c).parentNode.parentNode.parentNode, false);}}

      &ScriptIrregular;
